package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.Reader;

import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    @Test
    public void testWithHeader() {
        // Given
        String[] header = {"Name", "Age", "Location"};
        CSVFormat csvFormat = CSVFormat.DEFAULT;

        // When
        CSVFormat result = csvFormat.withHeader(header);

        // Then
        assertNotSame(csvFormat, result);
        assertArrayEquals(header, result.getHeader());
    }

    @Test
    public void testWithHeader_EmptyHeader() {
        // Given
        String[] header = {};
        CSVFormat csvFormat = CSVFormat.DEFAULT;

        // When
        CSVFormat result = csvFormat.withHeader(header);

        // Then
        assertNotSame(csvFormat, result);
        assertArrayEquals(header, result.getHeader());
    }

    @Test
    public void testWithHeader_NullHeader() {
        // Given
        String[] header = null;
        CSVFormat csvFormat = CSVFormat.DEFAULT;

        // When
        CSVFormat result = csvFormat.withHeader(header);

        // Then
        assertNotSame(csvFormat, result);
        assertNull(result.getHeader());
    }

    @Test
    public void testWithHeader_ReflectiveInvocation() throws Exception {
        // Given
        String[] header = {"Name", "Age", "Location"};
        CSVFormat csvFormat = CSVFormat.DEFAULT;
        CSVFormat csvFormatSpy = spy(csvFormat);

        // When
        CSVFormat result = (CSVFormat) CSVFormat.class.getDeclaredMethod("withHeader", String[].class)
                .invoke(csvFormatSpy, (Object) header);

        // Then
        assertNotSame(csvFormat, result);
        assertArrayEquals(header, result.getHeader());
    }
}
